// Simulación de alerta interna de stock crítico
const body = $input.first().json.body || $input.first().json;

const nivel = body.stock_actual === 0 ? 'SIN_STOCK' : 'STOCK_MINIMO';

const alerta = {
  tipo: nivel,
  producto: `${body.marca} — ${body.nombre}`,
  stock_actual: body.stock_actual,
  stock_minimo: body.stock_minimo,
  deficit: body.deficit,
  mensaje: body.stock_actual === 0
    ? `URGENTE: ${body.nombre} sin stock. Reabastecer inmediatamente.`
    : `AVISO: ${body.nombre} en stock mínimo (${body.stock_actual}/${body.stock_minimo}).`
};

console.log('[ÓPTICA DEMO] Alerta de stock:');
console.log(JSON.stringify(alerta, null, 2));

return [{
  json: {
    ok: true,
    tipo: 'ALERTA_STOCK',
    nivel,
    producto_id: body.producto_id,
    producto: alerta.producto,
    deficit: body.deficit,
    timestamp: new Date().toISOString()
  }
}];
